observation.old_content:
lexer grammar SYsULexer;

@lexer::members {
    std::string currentFilename = "<unknown>";
    int currentLine = 1;
    int currentCol = 1;
    bool atStartOfLine = true;
    bool hadLeadingSpace = false;
}

Int : 'int';
Return : 'return';

LeftParen : '(';
RightParen : ')';
LeftBracket : '[';
RightBracket : ']';
LeftBrace : '{';
RightBrace : '}';

Plus : '+';

Semi : ';';
Comma : ',';

Equal : '=';

Identifier
    :   IdentifierNondigit
        (   IdentifierNondigit
        |   Digit
        )*
    ;

fragment
IdentifierNondigit
    :   Nondigit
    ;

fragment
Nondigit
    :   [a-zA-Z_]
    ;

fragment
Digit
    :   [0-9]
    ;

Constant
    :   IntegerConstant
    ;

fragment
IntegerConstant
    :   DecimalConstant
    |   OctalConstant
    ;

fragment
DecimalConstant
    :   NonzeroDigit Digit*
    ;

fragment
OctalConstant
    :   '0' OctalDigit*
    ;


fragment
NonzeroDigit
    :   [1-9]
    ;

fragment
OctalDigit
    :   [0-7]
    ;


// 预处理信息处理，可以从预处理信息中获得文件名以及行号
// 预处理信息中的第一个数字即为行号
LineAfterPreprocessing
    :   '#' Whitespace* ~[\r\n]*
        {
            // Extract line number and filename from preprocessor directive
            std::string text = getText();
            std::istringstream iss(text.substr(1));
            int lineNum;
            std::string filename;

            if (iss >> lineNum) {
                currentLine = lineNum;

                // Extract filename (may be quoted)
                std::getline(iss, filename);

                // Remove flags part
                size_t spacePos = filename.find(' ');
                if (spacePos != std::string::npos) {
                    filename = filename.substr(0, spacePos);
                }

                // Remove quotes if present
                if (filename.size() >= 2 && filename.front() == '"' && filename.back() == '"') {
                    filename = filename.substr(1, filename.size() - 2);
                }

                currentFilename = filename;
                currentCol = 1;
                atStartOfLine = true;
                hadLeadingSpace = false;
            }
        }
        -> skip
    ;

Whitespace
    :   [ \t]+
        {
            hadLeadingSpace = true;
            currentCol += getText().size();
        }
        -> skip
    ;

// 换行符号，可以利用这个信息来更新行号
Newline
    :   (   '\r' '\n'?
        |   '\n'
        )
        {
            currentLine++;
            currentCol = 1;
            atStartOfLine = true;
            hadLeadingSpace = false;
        }
        -> skip
    ;

